class Admin_Model_Category extends Admin_Model_Base_Category {

    const CATEGORY_SALE = 9835;
    const MENU_CATEGORIES_ID = [1, 2, 3, 4];



    /**
     * @param Doctrine_Connection|null $conn
     */
    public function save(Doctrine_Connection $conn = null) {
        $isNew = $this->ID == null;

        $this->DateTimeUpdated = date('Y-m-d H:i:s');

        parent::save($conn);

        if ( $isNew ) {
            $this->DateTimeCreated = date('Y-m-d H:i:s');
            foreach (ModelEshop::getEshops() as $eshop) {
                $categoryEshop = new CategoryEshop();
                $categoryEshop->Eshop_ID = $eshop->ID;
                $categoryEshop->Category_ID = $this->ID;
                $categoryEshop->Active = true;
                $categoryEshop->save();
            }
        }
    }

    /**
     * Vrací produkty pro sitemapy
     * @param ModelEshop|null $eshop
     * @return array
     */
    public static function loadCategoriesSitemap(?ModelEshop $eshop = null) :array {
        if ( !$eshop )
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Category object');
        $query->select('categoryLangs.slug, object.ID, subCategories.ID, subCategoryLangs.slug');
        $query->innerJoin('object.categoryEshops categoryEshops WITH categoryEshops.Eshop_ID = ? AND categoryEshops.Active = ?', [$eshop->ID, true]);
        $query->innerJoin('object.categoryLangs categoryLangs WITH categoryLangs.Language_ID = ?', [$eshop->Language_ID]);

        $query->leftJoin('object.categories subCategories WITH subCategories.Category_ID = object.ID');
        $query->innerJoin('subCategories.categoryEshops subCategoryEshops WITH subCategoryEshops.Eshop_ID = ? AND subCategoryEshops.Active = ?', [$eshop->ID, true]);
        $query->innerJoin('subCategories.categoryLangs subCategoryLangs WITH subCategoryLangs.Language_ID = ?', [$eshop->Language_ID]);

        return $query->execute()->toArray();
    }

    /**
     * @param string $slug
     * @param Eshop|null $eshop
     * @return array
     */
    public static function getCategoryBySlug(string $slug, Eshop $eshop = null): array {
        if ( !$eshop )
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Category object');
        $query->select('object.*, file.*, categoryLangs.*, categoryEshops.*, categories.*, subCategoryLangs.*');
        $query->addSelect('categoryLangs.Name as Name, categoryLangs.Description as Description, categoryLangs.ShortDescription as ShortDescription, categoryLangs.slug as slug');
        $query->addSelect('categoryLangs.H1Name as H1Name, categoryLangs.Title as Title, categoryLangs.MetaDescription as MetaDescription');
        $query->addSelect('categoryEshops.Active as Active');
        $query->leftJoin('object.file file');
        $query->leftJoin('object.categoryLangs categoryLangs WITH categoryLangs.Language_ID = ?', $eshop->Language_ID);
        $query->leftJoin('object.categoryEshops categoryEshops WITH categoryEshops.Eshop_ID = ?', $eshop->ID);
        $query->where('categoryLangs.slug = ?', $slug);
        $query->andWhere('categoryEshops.Active = ?', true);
        $query->leftJoin('object.categories categories');
        $query->leftJoin('categories.categoryLangs subCategoryLangs WITH subCategoryLangs.Language_ID = ?', $eshop->Language_ID);
        $category = $query->execute()->toArray();

        return $category ? $category[0] : [];
    }

