    }

    /**
     * @param Eshop|null $eshop
     * @return array
     */
    public static function getMainMenuCategories(Eshop $eshop = null): array {
        if (!$eshop)
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Category object');
        $query->select('object.*, object.Category_ID as Parent_ID, file.*, categoryLangs.Name as Name, categoryLangs.Rank as Rank, categoryLangs.slug as slug');
        $query->leftJoin('object.file file');
        $query->leftJoin('object.categoryLangs categoryLangs WITH categoryLangs.Language_ID = ?', $eshop->Language_ID);
        $query->leftJoin('object.categoryEshops categoryEshops WITH categoryEshops.Eshop_ID = ? AND categoryEshops.Active = ?', [$eshop->ID, true]);
        $query->andWhere('categoryEshops.Active = ?', true);
        $query->addOrderBy('categoryEshops.Rank ASC');

        $allCategories = $query->execute([], Doctrine_Core::HYDRATE_ARRAY);

        $categoriesById = [];
        foreach ($allCategories as $category) {
            $category['categories'] = [];
            $categoriesById[$category['ID']] = $category;
        }

        $rootCategories = [];

        foreach ($allCategories as $category) {
            $parentId = $category['Parent_ID'];

            if ($parentId === null) {
                // Kořenová kategorie
                $rootCategories[] = &$categoriesById[$category['ID']];
            } else {
                if (isset($categoriesById[$parentId])) {
                    $categoriesById[$parentId]['categories'][] = &$categoriesById[$category['ID']];
                }
            }
        }

        self::sortCategoriesByRank($rootCategories);

        return $rootCategories;

    }

    public static function sortCategoriesByRank(array &$categories) {
        usort($categories, function ($a, $b) {
            return ($a['Rank'] ?? 0) <=> ($b['Rank'] ?? 0);
        });

        foreach ($categories as &$category) {
            if (!empty($category['categories'])) {
                self::sortCategoriesByRank($category['categories']);
            }
        }
    }

