    /**
     * @return array
     */
    public static function formatCategoryTree(): array {
        $query = Doctrine_Query::create();
        $query->select('object.ID, object.Category_ID, categoryLangs.Name as Name');
        $query->from('Admin_Model_Category object');
        $query->leftJoin('object.categoryLangs categoryLangs WITH Language_ID = 1');
        $resultArray = $query->execute()->toArray();

        $result = array();
        foreach ($resultArray as $item) {
            $itemItem = array();
            $itemItem['id'] = $item['ID'];
            $itemItem['Category_ID'] = $item['Category_ID'];
            $itemItem['text'] = $item['Name'];
            $result[] = $itemItem;
        }

        $dangling = array();
        $output = array();

        foreach ($result as $entry) {
            $entry['children'] = array();
            $id = $entry['id'];

            if ($entry['Category_ID'] == '') {
                $all[$id] = $entry;
                $output[] = & $all[$id];
            } else {
                $dangling[$id] = $entry;
            }
        }

        while (count($dangling) > 0) {
            foreach ($dangling as $entry) {
                $id = $entry['id'];
                $pid = $entry['Category_ID'];

                if (isset($all[$pid])) {
                    $all[$id] = $entry;
                    $all[$pid]['children'][] = & $all[$id];
                    unset($dangling[$entry['id']]);
                }
            }
        }

        return $output;
    }

    public static function getCategoryByCode(string $categoryCode) {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Category object');
        $query->select('object.*, categoryLangs.Name as Name');
        $query->leftJoin('object.categoryLangs categoryLangs WITH categoryLangs.Language_ID = 1');
        $query->where('object.Code = ?', $categoryCode);

        return $query->fetchOne();
    }

    public static function getCategoryByIdOrCode(?int $categoryID = null, ?string $categoryCode = null):self {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Category object');
        $query->select('object.*, categoryLangs.Name as Name');
        $query->leftJoin('object.categoryLangs categoryLangs WITH categoryLangs.Language_ID = 1');
        if($categoryID)
            $query->where('object.ID = ?', $categoryID);
        else
            $query->where('object.Code = ?', $categoryCode);
        return $query->fetchOne();
    }

    public static function getCategories($id = null, $filter = null, $changedSince =null): Doctrine_Collection {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Category object');
        $query->select('object.*, categoryLangs.Name as Name');
        $query->leftJoin('object.categoryLangs categoryLangs WITH categoryLangs.Language_ID = 1');
        $query->where('object.Archived IS NOT TRUE');

        if ($id) {
            $query->where('object.ID = ?', $id);
        }

        //ToDo filter jak má fungovat?
        if ($filter) {
            $query->where('object.Code = ?', $filter);
        }

        if ($changedSince) {
            $query->andWhere('object.DateTimeUpdated > ?', $changedSince);
        }

        return $query->execute();

    }

