    public static function getCategoryByOldHistorySlug(string $slug) {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_CategorySlugHistory object');
        $query->addSelect('object.Category_ID, categoryLangs.slug as slug');
        $query->leftJoin('object.category category');
        $query->leftJoin('category.categoryLangs categoryLangs WITH categoryLangs.Language_ID = ?', Eshop::getInstance()->getEshop()->Language_ID);
        $query->where('object.Slug = ?', $slug);
        $query->limit(1);
        $result = $query->execute([], Doctrine_Core::HYDRATE_ARRAY);
        if($result) {
            return $result[0];
        } else {
            return null;
        }

    }


